checker_dsl:
OR {
  EXISTS (`ExposedFieldAccess A`, `Expr ENTRY`, `ClassAnnotatedAsThreadSafe CLS`, `ExposedField F`) {
    AND {
      (`CLS is a Class and has an annotation whose type name is "ThreadSafe"`),
      (`F is a Field declared in CLS, not volatile, and its type is not a LockType`),
      (`F's type is not a thread-safe type, the type of initialValue(F) is not a thread-safe type, and initialValue(F) is not a thread-safe initializer (e.g., Collections.synchronized* call)`),
      OR {
        AND {
          (`CLS.unlockedPublicAccess(F, ENTRY, _, A, true) holds, A is a FieldAccess, A's field is F, and A = ENTRY`),
          EXISTS (`Method M`) {
            AND {
              (`M is declared in CLS`),
              (`M is public`),
              (`M = ENTRY's enclosing callable`),
              NOT { (`ENTRY is locally monitored`) },
              OR {
                AND {
                  (`F is declared in CLS`),
                  (`Modification::isModifying(A) is true`)
                },
                EXISTS (`MethodCall C`, `Expr E0`, `Method M0`) {
                  AND {
                    (`CLS.unlockedAccess(F, E0, M0, A, true) holds`),
                    (`M = C's enclosing callable`),
                    (`M0 is not public`),
                    (`C's callee's source declaration is M0`),
                    (`C = ENTRY`),
                    NOT { (`E0 is locally monitored`) }
                  }
                }
              }
            }
          }
        },
        AND {
          (`CLS.unlockedPublicAccess(F, ENTRY, _, A, false) holds, A is a FieldAccess, A's field is F, and A = ENTRY`),
          (`CLS.hasPublicWriteAccess(F) holds`),
          EXISTS (`Method M`) {
            AND {
              (`M is declared in CLS`),
              (`M is public`),
              (`M = ENTRY's enclosing callable`),
              NOT { (`ENTRY is locally monitored`) },
              OR {
                AND {
                  (`F is declared in CLS`),
                  (`Modification::isModifying(A) is false`)
                },
                EXISTS (`MethodCall C`, `Expr E0`, `Method M0`) {
                  AND {
                    (`CLS.unlockedAccess(F, E0, M0, A, false) holds`),
                    (`M = C's enclosing callable`),
                    (`M0 is not public`),
                    (`C's callee's source declaration is M0`),
                    (`C = ENTRY`),
                    NOT { (`E0 is locally monitored`) }
                  }
                }
              }
            }
          },
          OR {
            (`CLS.hasUnlockedPublicAccess(F, _, _, true) holds`),
            (`CLS.hasOnelockedPublicAccess(F, _, _, true, _) holds`),
            EXISTS (`Method M_PUB`) {
              AND {
                (`M_PUB is declared in CLS`),
                (`M_PUB is public`),
                (`CLS.hasOnepluslockedAccess(F, _, M_PUB, true, _) holds`)
              }
            }
          }
        }
      }
    }
  },
  EXISTS (`ExposedField F`, `ClassAnnotatedAsThreadSafe CLS`) {
    AND {
      (`CLS is a Class and has an annotation whose type name is "ThreadSafe"`),
      (`F is a Field declared in CLS, not volatile, and its type is not a LockType`),
      (`F's type is not a thread-safe type, the type of initialValue(F) is not a thread-safe type, and initialValue(F) is not a thread-safe initializer (e.g., Collections.synchronized* call)`),
      OR {
        (`CLS.singleMonitorMismatch(F) holds`),
        AND {
          (`CLS.notFullyMonitored(F) holds`),
          (`CLS.hasPublicWriteAccess(F) holds`),
          OR {
            (`CLS.hasUnlockedPublicAccess(F, _, _, true) holds`),
            (`CLS.hasOnelockedPublicAccess(F, _, _, true, _) holds`),
            EXISTS (`Method M_PUB`) {
              AND {
                (`M_PUB is declared in CLS`),
                (`M_PUB is public`),
                (`CLS.hasOnepluslockedAccess(F, _, M_PUB, true, _) holds`)
              }
            }
          }
        }
      }
    }
  }
}
